import { GenerativeUiScreen } from "@/components/generative-ui/generative-ui-screen";

export default function GenerativeUiPage() {
  return <GenerativeUiScreen />;
}

import { handleGenerativeUiRequest } from "@/lib/generative-ui/runtime";

export const runtime = "nodejs";

export function POST(request: Request) {
  return handleGenerativeUiRequest(request);
}

import { TooltipProvider } from "@/components/ui/tooltip";

import { DemoWorkspaceShell } from "@/components/demo-workspace-shell";
import { getGenerativeUiRuntimeState } from "@/lib/generative-ui/runtime";
import { GenerativeUiWorkspace } from "@/components/generative-ui/generative-ui-workspace";

export function GenerativeUiScreen() {
  const runtimeState = getGenerativeUiRuntimeState();

  return (
    <TooltipProvider>
      <DemoWorkspaceShell
        badges={[runtimeState.statusLabel, runtimeState.chatModel]}
        breadcrumbClassName="font-heading text-xs tracking-[0.16em]"
        breadcrumbTitle="Generative UI"
        headerFrame="card"
        summary="A chat workspace where the model can use hosted web search when recency matters, then render either a comparison matrix or recommendation card through AI SDK UI tool parts."
        title="Model-selected interface components inside the message stream"
      >
        <GenerativeUiWorkspace
          chatModel={runtimeState.chatModel}
          isChatAvailable={runtimeState.isChatAvailable}
          nodeVersion={runtimeState.nodeVersion}
          setupMessage={runtimeState.setupMessage}
        />
      </DemoWorkspaceShell>
    </TooltipProvider>
  );
}

"use client";

import {
  Conversation,
  ConversationContent,
  ConversationEmptyState,
  ConversationScrollButton,
} from "@/components/ai-elements/conversation";
import {
  Message,
  MessageContent,
  MessageResponse,
} from "@/components/ai-elements/message";
import {
  PromptInput,
  PromptInputBody,
  PromptInputFooter,
  PromptInputSubmit,
  PromptInputTextarea,
} from "@/components/ai-elements/prompt-input";
import {
  Reasoning,
  ReasoningContent,
  ReasoningTrigger,
} from "@/components/ai-elements/reasoning";
import {
  Source,
  Sources,
  SourcesContent,
  SourcesTrigger,
} from "@/components/ai-elements/sources";
import {
  Tool,
  ToolContent,
  ToolHeader,
  ToolInput,
  ToolOutput,
} from "@/components/ai-elements/tool";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Separator } from "@/components/ui/separator";
import type { UIMessage } from "ai";
import {
  BotIcon,
  RefreshCwIcon,
  SearchIcon,
  SparklesIcon,
  SquareIcon,
} from "lucide-react";
import type { ReactNode } from "react";

import {
  ConversationErrorMessage,
  useConversationErrorRetry,
} from "@/components/demo-chat/conversation-error-message";

import { FeatureComparisonMatrix } from "@/components/generative-ui/feature-comparison-matrix";
import {
  featureComparisonToolPartType,
  type GenerativeUiToolPart,
  planRecommendationToolPartType,
  projectGenerativeUiMessage,
} from "@/components/generative-ui/message-parts";
import { PlanRecommendationCard } from "@/components/generative-ui/plan-recommendation-card";
import { useGenerativeUiChat } from "@/components/generative-ui/use-generative-ui-chat";

const generativeUiSamplePrompts = [
  "Compare the current AI app builder options for a small SaaS team.",
  "Which AI coding assistant should I pick this month for a TypeScript monorepo?",
  "Compare RAG, tool calling, and workflow agents for a support chatbot.",
  "Recommend the best agent pattern for a demo that must ship in 30 minutes.",
] as const;

function getLatestAssistantMessage(messages: UIMessage[]) {
  for (let index = messages.length - 1; index >= 0; index -= 1) {
    const message = messages[index];

    if (message?.role === "assistant") {
      return message;
    }
  }

  return;
}

function getToolDisplayTitle(partType: string) {
  if (partType === "tool-web_search") {
    return "Web search";
  }

  return "Auxiliary tool";
}

function renderGenerativeUiToolPart(part: GenerativeUiToolPart) {
  if (part.type === featureComparisonToolPartType) {
    return <FeatureComparisonMatrix key={part.toolCallId} part={part} />;
  }

  if (part.type === planRecommendationToolPartType) {
    return <PlanRecommendationCard key={part.toolCallId} part={part} />;
  }

  return null;
}

function GenerativeUiSources({
  sources,
}: {
  sources: ReturnType<typeof projectGenerativeUiMessage>["sourceUrlParts"];
}) {
  if (sources.length === 0) {
    return null;
  }

  return (
    <Sources>
      <SourcesTrigger count={sources.length} />
      <SourcesContent>
        {sources.map((source) => (
          <Source
            href={source.url}
            key={`${source.sourceId}-${source.url}`}
            title={source.title ?? source.url}
          />
        ))}
      </SourcesContent>
    </Sources>
  );
}

function GenerativeUiAssistantMessage({
  isStreaming,
  message,
}: {
  isStreaming: boolean;
  message: UIMessage;
}) {
  const projection = projectGenerativeUiMessage(message);
  const hasVisibleOutput =
    projection.reasoningText.length > 0 ||
    projection.text.length > 0 ||
    projection.uiToolParts.length > 0 ||
    projection.sourceUrlParts.length > 0 ||
    projection.auxiliaryToolParts.length > 0;
  const isReasoningStreaming =
    isStreaming && message.parts.at(-1)?.type === "reasoning";

  return (
    <div className="space-y-4">
      {projection.reasoningText ? (
        <Reasoning className="w-full" isStreaming={isReasoningStreaming}>
          <ReasoningTrigger />
          <ReasoningContent>{projection.reasoningText}</ReasoningContent>
        </Reasoning>
      ) : null}

      {projection.text ? (
        <MessageResponse>{projection.text}</MessageResponse>
      ) : null}

      {projection.uiToolParts.map(renderGenerativeUiToolPart)}

      <GenerativeUiSources sources={projection.sourceUrlParts} />

      {projection.auxiliaryToolParts.map((part) => (
        <Tool className="bg-muted/20" key={part.toolCallId}>
          {part.type === "dynamic-tool" ? (
            <ToolHeader
              state={part.state}
              title={part.toolName}
              toolName={part.toolName}
              type={part.type}
            />
          ) : (
            <ToolHeader
              state={part.state}
              title={getToolDisplayTitle(part.type)}
              type={part.type}
            />
          )}
          <ToolContent>
            {part.input ? <ToolInput input={part.input} /> : null}
            <ToolOutput errorText={part.errorText} output={part.output} />
          </ToolContent>
        </Tool>
      ))}

      {hasVisibleOutput ? null : (
        <p className="text-muted-foreground text-sm">
          {isStreaming ? "Thinking..." : "Waiting for visible output."}
        </p>
      )}
    </div>
  );
}

function GenerativeUiMessage({
  isStreaming,
  message,
}: {
  isStreaming: boolean;
  message: UIMessage;
}) {
  const projection = projectGenerativeUiMessage(message);
  let messageBody: ReactNode;

  if (message.role === "assistant") {
    messageBody = (
      <GenerativeUiAssistantMessage
        isStreaming={isStreaming}
        message={message}
      />
    );
  } else if (projection.text) {
    messageBody = <MessageResponse>{projection.text}</MessageResponse>;
  } else {
    messageBody = (
      <p className="text-muted-foreground text-sm">
        Waiting for visible output.
      </p>
    );
  }

  return (
    <Message from={message.role} key={message.id}>
      <MessageContent
        className={
          message.role === "assistant"
            ? "w-full max-w-4xl overflow-visible"
            : "max-w-2xl"
        }
      >
        {messageBody}
      </MessageContent>
    </Message>
  );
}

export interface GenerativeUiWorkspaceProps {
  chatModel: string;
  isChatAvailable: boolean;
  nodeVersion: string;
  setupMessage: string | null;
}

export function GenerativeUiWorkspace({
  chatModel,
  isChatAvailable,
  nodeVersion,
  setupMessage,
}: GenerativeUiWorkspaceProps) {
  const {
    clearError,
    error,
    hasMessages,
    isBusy,
    messages,
    regenerate,
    sendMessage,
    status,
    stop,
  } = useGenerativeUiChat();
  const retryConversationError = useConversationErrorRetry({
    clearError,
    regenerate,
  });
  const latestAssistantMessage = getLatestAssistantMessage(messages);

  return (
    <div className="grid min-h-[70svh] min-w-0 gap-4 lg:h-full lg:min-h-0 lg:grid-cols-[minmax(0,1fr)_19rem]">
      <section className="flex min-h-[70svh] min-w-0 flex-col border border-foreground/10 bg-background lg:h-full lg:min-h-0">
        {isChatAvailable ? null : (
          <div className="border-foreground/10 border-b px-4 py-3 text-muted-foreground text-xs/relaxed">
            {setupMessage}
          </div>
        )}

        <Conversation className="min-h-0">
          <ConversationContent className="mx-auto flex w-full max-w-4xl flex-1 gap-6 px-4 py-6">
            {hasMessages || error ? (
              <>
                {messages.map((message) => (
                  <GenerativeUiMessage
                    isStreaming={
                      status === "streaming" &&
                      message.id === latestAssistantMessage?.id
                    }
                    key={message.id}
                    message={message}
                  />
                ))}
                {error ? (
                  <ConversationErrorMessage
                    error={error}
                    isRetryDisabled={isBusy || !isChatAvailable}
                    onRetry={retryConversationError}
                  />
                ) : null}
              </>
            ) : (
              <ConversationEmptyState
                description="Ask for a comparison or a recommendation. Current questions can use search before the visual answer is generated."
                icon={<SparklesIcon className="size-5" />}
                title="Generative UI workspace is ready"
              />
            )}
          </ConversationContent>
          <ConversationScrollButton />
        </Conversation>

        <div className="border-foreground/10 border-t px-4 py-4">
          <div className="mx-auto w-full max-w-4xl">
            <PromptInput onSubmit={({ text }) => sendMessage({ text })}>
              <PromptInputBody>
                <PromptInputTextarea
                  disabled={!isChatAvailable || isBusy}
                  placeholder="Ask for a comparison, recommendation, or current research-backed decision."
                />
              </PromptInputBody>
              <PromptInputFooter className="flex items-center justify-between gap-3 border-foreground/10 border-t px-3 py-3">
                <div className="flex flex-wrap items-center gap-2">
                  <Badge variant="outline">AI SDK 6</Badge>
                  <Badge variant="outline">Generative UI</Badge>
                  <Badge variant="outline">{chatModel}</Badge>
                </div>
                <div className="flex items-center gap-2">
                  {isBusy ? (
                    <Button
                      onClick={stop}
                      size="sm"
                      type="button"
                      variant="outline"
                    >
                      <SquareIcon className="size-3.5" />
                      Stop
                    </Button>
                  ) : null}
                  {hasMessages ? (
                    <Button
                      onClick={() => regenerate()}
                      size="sm"
                      type="button"
                      variant="outline"
                    >
                      <RefreshCwIcon className="size-3.5" />
                      Retry
                    </Button>
                  ) : null}
                  <PromptInputSubmit
                    disabled={!isChatAvailable}
                    status={status}
                  />
                </div>
              </PromptInputFooter>
            </PromptInput>

            {hasMessages ? null : (
              <div className="mt-3 grid gap-2 sm:grid-cols-2">
                {generativeUiSamplePrompts.map((prompt) => (
                  <Button
                    className="h-auto justify-start whitespace-normal py-2 text-left"
                    disabled={!isChatAvailable || isBusy}
                    key={prompt}
                    onClick={() => sendMessage({ text: prompt })}
                    size="sm"
                    type="button"
                    variant="outline"
                  >
                    <BotIcon className="size-3.5 shrink-0" />
                    {prompt}
                  </Button>
                ))}
              </div>
            )}
          </div>
        </div>
      </section>

      <aside className="min-w-0 border border-foreground/10 bg-background p-4 lg:min-h-0 lg:overflow-y-auto">
        <div className="space-y-4">
          <div>
            <p className="text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
              Runtime
            </p>
            <p className="mt-1 font-medium text-sm">{nodeVersion}</p>
          </div>
          <div>
            <p className="text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
              Tools
            </p>
            <div className="mt-2 flex flex-wrap gap-2">
              <Badge variant="outline">showFeatureComparison</Badge>
              <Badge variant="outline">showPlanRecommendation</Badge>
              <Badge variant="outline">
                <SearchIcon className="size-3" />
                web_search
              </Badge>
            </div>
          </div>
          <Separator />
          <div>
            <p className="text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
              Output
            </p>
            <p className="mt-1 text-muted-foreground text-sm">
              Comparison matrix or recommendation card, selected by the model
              during the chat run.
            </p>
          </div>
        </div>
      </aside>
    </div>
  );
}

"use client";

import { Badge } from "@/components/ui/badge";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { cn } from "@/lib/utils";
import { Table2Icon } from "lucide-react";

import type {
  FeatureComparisonInput,
  FeatureComparisonOutput,
} from "@/lib/generative-ui/ui-contract";
import {
  featureComparisonToolPartType,
  type GenerativeUiToolPart,
} from "./message-parts";
import {
  getGeneratedString,
  isRecord,
  SkeletonLine,
} from "./partial-rendering";

interface FeatureComparisonMatrixProps {
  part: GenerativeUiToolPart;
}

type PartialComparisonCriterion = Partial<
  FeatureComparisonInput["criteria"][number]
> & {
  scores?: Partial<
    FeatureComparisonInput["criteria"][number]["scores"][number]
  >[];
};

type PartialFeatureComparison = Partial<FeatureComparisonInput> & {
  criteria?: PartialComparisonCriterion[];
  options?: Partial<FeatureComparisonInput["options"][number]>[];
};

type ComparisonRenderState = "final" | "streaming" | "validating";

const ratingLabels: Record<string, string> = {
  best: "Best",
  mixed: "Mixed",
  strong: "Strong",
  weak: "Weak",
};

const ratingClassNames: Record<string, string> = {
  best: "border-emerald-500/30 bg-emerald-500/10 text-emerald-700 dark:text-emerald-300",
  mixed:
    "border-amber-500/30 bg-amber-500/10 text-amber-700 dark:text-amber-300",
  strong: "border-sky-500/30 bg-sky-500/10 text-sky-700 dark:text-sky-300",
  weak: "border-rose-500/30 bg-rose-500/10 text-rose-700 dark:text-rose-300",
};

function isFeatureComparisonOutput(
  value: unknown
): value is FeatureComparisonOutput {
  if (!value || typeof value !== "object") {
    return false;
  }

  const output = value as FeatureComparisonOutput;

  return (
    output.kind === "feature-comparison" &&
    typeof output.subject === "string" &&
    typeof output.summary === "string" &&
    Array.isArray(output.options) &&
    Array.isArray(output.criteria)
  );
}

function renderPendingComparison() {
  return (
    <section className="not-prose overflow-hidden rounded-md border border-foreground/10 bg-muted/20">
      <div className="flex items-center justify-between gap-3 border-foreground/10 border-b px-4 py-3">
        <div className="flex items-center gap-2">
          <Table2Icon className="size-4 text-muted-foreground" />
          <span className="font-medium text-sm">Preparing comparison</span>
        </div>
        <Badge variant="outline">Working</Badge>
      </div>
      <div className="space-y-2 p-4">
        <div className="h-3 w-2/3 rounded bg-muted" />
        <div className="h-16 rounded bg-muted/70" />
      </div>
    </section>
  );
}

function renderComparisonError() {
  return (
    <section className="not-prose rounded-md border border-destructive/30 bg-destructive/5 p-4 text-destructive text-sm">
      Comparison output could not be finalized.
    </section>
  );
}

function getFeatureComparisonDraft(part: GenerativeUiToolPart) {
  if (part.state === "output-available") {
    return {
      data: part.output,
      renderState: "final" as const,
    };
  }

  if (
    (part.state === "input-streaming" || part.state === "input-available") &&
    isRecord(part.input)
  ) {
    return {
      data: part.input as PartialFeatureComparison,
      renderState:
        part.state === "input-available"
          ? ("validating" as const)
          : ("streaming" as const),
    };
  }

  return;
}

function getBadgeLabel(renderState: ComparisonRenderState) {
  if (renderState === "streaming") {
    return "Generating";
  }

  if (renderState === "validating") {
    return "Validating";
  }

  return "Comparison generated";
}

function getRatingLabel(rating: unknown) {
  const ratingValue = getGeneratedString(rating);

  return ratingValue ? ratingLabels[ratingValue] : undefined;
}

function renderScoreCell(
  score: Partial<
    FeatureComparisonInput["criteria"][number]["scores"][number]
  > | null,
  renderState: ComparisonRenderState
) {
  if (!score) {
    return renderState === "final" ? (
      <span className="text-muted-foreground">No score</span>
    ) : (
      <SkeletonLine className="w-3/4" />
    );
  }

  const rating = getGeneratedString(score.rating);
  const ratingLabel = getRatingLabel(score.rating);
  const summary = getGeneratedString(score.summary);

  return (
    <div className="space-y-2">
      {ratingLabel ? (
        <Badge
          className={cn("rounded-full", rating && ratingClassNames[rating])}
          variant="outline"
        >
          {ratingLabel}
        </Badge>
      ) : (
        <SkeletonLine className="w-20" />
      )}
      <div className="text-muted-foreground">
        {summary ?? <SkeletonLine className="w-4/5" />}
      </div>
    </div>
  );
}

function renderComparisonContent(
  output: PartialFeatureComparison,
  renderState: ComparisonRenderState
) {
  const subject = getGeneratedString(output.subject);
  const summary = getGeneratedString(output.summary);
  const options = Array.isArray(output.options) ? output.options : [];
  const criteria = Array.isArray(output.criteria) ? output.criteria : [];
  const visibleOptions = options.length > 0 ? options : [undefined];
  const visibleCriteria = criteria.length > 0 ? criteria : [undefined];

  return (
    <section className="not-prose overflow-hidden rounded-md border border-foreground/10 bg-background">
      <div className="space-y-2 border-foreground/10 border-b px-4 py-3">
        <div className="flex min-w-0 items-center justify-between gap-3">
          <div className="flex min-w-0 items-center gap-2">
            <Table2Icon className="size-4 shrink-0 text-muted-foreground" />
            <h3 className="min-w-0 flex-1 truncate font-medium text-sm">
              {subject ?? <SkeletonLine className="w-48 max-w-full" />}
            </h3>
          </div>
          <Badge variant="outline">{getBadgeLabel(renderState)}</Badge>
        </div>
        <div className="text-muted-foreground text-sm">
          {summary ?? <SkeletonLine className="w-2/3" />}
        </div>
      </div>

      <div className="max-w-full overflow-x-auto">
        <Table className="min-w-[42rem]">
          <TableHeader>
            <TableRow>
              <TableHead className="w-44 whitespace-normal break-words">
                Criterion
              </TableHead>
              {visibleOptions.map((option, index) => {
                const optionName = getGeneratedString(option?.name);
                const optionSummary = getGeneratedString(option?.summary);

                return (
                  <TableHead
                    className="whitespace-normal break-words"
                    key={optionName ?? `option-${index}`}
                  >
                    <div className="space-y-1">
                      <div className="font-medium text-foreground">
                        {optionName ?? <SkeletonLine className="w-28" />}
                      </div>
                      <div className="text-muted-foreground text-xs">
                        {optionSummary ?? <SkeletonLine className="w-32" />}
                      </div>
                    </div>
                  </TableHead>
                );
              })}
            </TableRow>
          </TableHeader>
          <TableBody>
            {visibleCriteria.map((criterion, criterionIndex) => (
              <TableRow
                key={
                  getGeneratedString(criterion?.label) ??
                  `criterion-${criterionIndex}`
                }
              >
                <TableCell className="whitespace-normal break-words align-top font-medium text-sm">
                  {getGeneratedString(criterion?.label) ?? (
                    <SkeletonLine className="w-28" />
                  )}
                </TableCell>
                {visibleOptions.map((option, optionIndex) => {
                  const optionName = getGeneratedString(option?.name);
                  const scores = Array.isArray(criterion?.scores)
                    ? criterion.scores
                    : [];
                  const score =
                    scores.find((item) => item.option === optionName) ??
                    scores[optionIndex] ??
                    null;

                  return (
                    <TableCell
                      className="min-w-48 whitespace-normal break-words align-top text-sm"
                      key={optionName ?? `score-${optionIndex}`}
                    >
                      {renderScoreCell(score, renderState)}
                    </TableCell>
                  );
                })}
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </div>
    </section>
  );
}

export function FeatureComparisonMatrix({
  part,
}: FeatureComparisonMatrixProps) {
  if (part.type !== featureComparisonToolPartType) {
    return null;
  }

  if (part.state === "output-error") {
    return renderComparisonError();
  }

  const draft = getFeatureComparisonDraft(part);

  if (!draft) {
    return renderPendingComparison();
  }

  if (draft.renderState === "final") {
    if (!isFeatureComparisonOutput(draft.data)) {
      return renderComparisonError();
    }

    return renderComparisonContent(draft.data, draft.renderState);
  }

  return renderComparisonContent(draft.data, draft.renderState);
}

"use client";

import { Badge } from "@/components/ui/badge";
import { CheckCircle2Icon, ListChecksIcon } from "lucide-react";

import type {
  PlanRecommendationInput,
  PlanRecommendationOutput,
} from "@/lib/generative-ui/ui-contract";
import {
  type GenerativeUiToolPart,
  planRecommendationToolPartType,
} from "./message-parts";
import {
  getGeneratedString,
  isRecord,
  SkeletonLine,
} from "./partial-rendering";

interface PlanRecommendationCardProps {
  part: GenerativeUiToolPart;
}

type PartialPlanRecommendation = Partial<PlanRecommendationInput> & {
  alternatives?: Partial<PlanRecommendationInput["alternatives"][number]>[];
  rationale?: Partial<PlanRecommendationInput["rationale"][number]>[];
  recommendedOption?: Partial<PlanRecommendationInput["recommendedOption"]>;
  risks?: Partial<PlanRecommendationInput["risks"][number]>[];
};

type RecommendationRenderState = "final" | "streaming" | "validating";

function isPlanRecommendationOutput(
  value: unknown
): value is PlanRecommendationOutput {
  if (!value || typeof value !== "object") {
    return false;
  }

  const output = value as PlanRecommendationOutput;

  return (
    output.kind === "plan-recommendation" &&
    typeof output.decision === "string" &&
    Array.isArray(output.alternatives) &&
    Array.isArray(output.nextSteps) &&
    Array.isArray(output.rationale) &&
    Array.isArray(output.risks) &&
    typeof output.recommendedOption?.name === "string"
  );
}

function renderPendingRecommendation() {
  return (
    <section className="not-prose overflow-hidden rounded-md border border-foreground/10 bg-muted/20">
      <div className="flex items-center justify-between gap-3 border-foreground/10 border-b px-4 py-3">
        <div className="flex items-center gap-2">
          <ListChecksIcon className="size-4 text-muted-foreground" />
          <span className="font-medium text-sm">Preparing recommendation</span>
        </div>
        <Badge variant="outline">Working</Badge>
      </div>
      <div className="space-y-2 p-4">
        <div className="h-3 w-3/4 rounded bg-muted" />
        <div className="h-20 rounded bg-muted/70" />
      </div>
    </section>
  );
}

function renderRecommendationError() {
  return (
    <section className="not-prose rounded-md border border-destructive/30 bg-destructive/5 p-4 text-destructive text-sm">
      Recommendation output could not be finalized.
    </section>
  );
}

function getPlanRecommendationDraft(part: GenerativeUiToolPart) {
  if (part.state === "output-available") {
    return {
      data: part.output,
      renderState: "final" as const,
    };
  }

  if (
    (part.state === "input-streaming" || part.state === "input-available") &&
    isRecord(part.input)
  ) {
    return {
      data: part.input as PartialPlanRecommendation,
      renderState:
        part.state === "input-available"
          ? ("validating" as const)
          : ("streaming" as const),
    };
  }

  return;
}

function getBadgeLabel(renderState: RecommendationRenderState) {
  if (renderState === "streaming") {
    return "Generating";
  }

  if (renderState === "validating") {
    return "Validating";
  }

  return "Recommendation generated";
}

function renderRiskMitigation(
  mitigation: unknown,
  renderState: RecommendationRenderState
) {
  const generatedMitigation = getGeneratedString(mitigation);

  if (generatedMitigation) {
    return (
      <p className="mt-1 text-muted-foreground text-sm">
        {generatedMitigation}
      </p>
    );
  }

  if (renderState === "final") {
    return null;
  }

  return (
    <div className="mt-1">
      <SkeletonLine className="w-3/4" />
    </div>
  );
}

function renderRecommendationContent(
  output: PartialPlanRecommendation,
  renderState: RecommendationRenderState
) {
  const decision = getGeneratedString(output.decision);
  const recommendedName = getGeneratedString(output.recommendedOption?.name);
  const recommendedSummary = getGeneratedString(
    output.recommendedOption?.summary
  );
  const rationale = Array.isArray(output.rationale) ? output.rationale : [];
  const alternatives = Array.isArray(output.alternatives)
    ? output.alternatives
    : [];
  const risks = Array.isArray(output.risks) ? output.risks : [];
  const nextSteps = Array.isArray(output.nextSteps) ? output.nextSteps : [];

  return (
    <section className="not-prose overflow-hidden rounded-md border border-foreground/10 bg-background">
      <div className="space-y-3 border-foreground/10 border-b px-4 py-4">
        <div className="flex min-w-0 items-center justify-between gap-3">
          <div className="flex min-w-0 items-center gap-2">
            <ListChecksIcon className="size-4 shrink-0 text-muted-foreground" />
            <h3 className="min-w-0 flex-1 truncate font-medium text-sm">
              {decision ?? <SkeletonLine className="w-48 max-w-full" />}
            </h3>
          </div>
          <Badge variant="outline">{getBadgeLabel(renderState)}</Badge>
        </div>
        <div className="rounded-md border border-emerald-500/20 bg-emerald-500/5 p-3">
          <div className="flex items-start gap-2">
            <CheckCircle2Icon className="mt-0.5 size-4 shrink-0 text-emerald-600" />
            <div className="w-full space-y-1">
              <p className="font-medium">
                {recommendedName ?? <SkeletonLine className="w-40" />}
              </p>
              <div className="text-muted-foreground text-sm">
                {recommendedSummary ?? <SkeletonLine className="w-2/3" />}
              </div>
            </div>
          </div>
        </div>
      </div>

      <div className="grid gap-4 p-4 md:grid-cols-2">
        <div className="space-y-3">
          <p className="text-muted-foreground text-xs uppercase tracking-[0.16em]">
            Rationale
          </p>
          <div className="space-y-2">
            {rationale.length > 0 ? (
              rationale.map((item, index) => (
                <div
                  className="rounded-md border border-foreground/10 p-3"
                  key={getGeneratedString(item.label) ?? `rationale-${index}`}
                >
                  <p className="font-medium text-sm">
                    {getGeneratedString(item.label) ?? (
                      <SkeletonLine className="w-28" />
                    )}
                  </p>
                  <div className="mt-1 text-muted-foreground text-sm">
                    {getGeneratedString(item.detail) ?? (
                      <SkeletonLine className="w-4/5" />
                    )}
                  </div>
                </div>
              ))
            ) : (
              <SkeletonLine className="h-16 w-full" />
            )}
          </div>
        </div>

        <div className="space-y-3">
          <p className="text-muted-foreground text-xs uppercase tracking-[0.16em]">
            Alternatives
          </p>
          <div className="space-y-2">
            {alternatives.length > 0 ? (
              alternatives.map((alternative, index) => (
                <div
                  className="rounded-md border border-foreground/10 p-3"
                  key={
                    getGeneratedString(alternative.name) ??
                    `alternative-${index}`
                  }
                >
                  <p className="font-medium text-sm">
                    {getGeneratedString(alternative.name) ?? (
                      <SkeletonLine className="w-28" />
                    )}
                  </p>
                  <div className="mt-1 text-muted-foreground text-sm">
                    {getGeneratedString(alternative.tradeoff) ?? (
                      <SkeletonLine className="w-4/5" />
                    )}
                  </div>
                </div>
              ))
            ) : (
              <SkeletonLine className="h-16 w-full" />
            )}
          </div>
        </div>

        {risks.length > 0 ? (
          <div className="space-y-3">
            <p className="text-muted-foreground text-xs uppercase tracking-[0.16em]">
              Risks
            </p>
            <div className="space-y-2">
              {risks.map((risk, index) => (
                <div
                  className="rounded-md border border-foreground/10 p-3"
                  key={getGeneratedString(risk.risk) ?? `risk-${index}`}
                >
                  <p className="font-medium text-sm">
                    {getGeneratedString(risk.risk) ?? (
                      <SkeletonLine className="w-32" />
                    )}
                  </p>
                  {renderRiskMitigation(risk.mitigation, renderState)}
                </div>
              ))}
            </div>
          </div>
        ) : null}

        <div className="space-y-3">
          <p className="text-muted-foreground text-xs uppercase tracking-[0.16em]">
            Next steps
          </p>
          <ol className="space-y-2">
            {nextSteps.length > 0 ? (
              nextSteps.map((step, index) => (
                <li className="flex gap-2 text-sm" key={step}>
                  <span className="flex size-5 shrink-0 items-center justify-center rounded-full border border-foreground/10 text-[11px]">
