export interface AiGatewayResolvedEnv {
  apiKey: string | undefined;
  baseURL: string;
  chatModel: string;
}

export interface AiGatewaySetupConfig {
  baseURL: string;
  chatModel: string;
}

export interface AiGatewayContractSetupState<
  TConfig extends AiGatewaySetupConfig = AiGatewaySetupConfig,
> {
  config: TConfig;
  isReady: boolean;
  issues: string[];
  nodeVersion: string;
}

export interface AiGatewayContractOptions<
  TConfig extends AiGatewaySetupConfig = AiGatewaySetupConfig,
> {
  buildConfig?: (
    resolvedEnv: AiGatewayResolvedEnv,
    env: AiGatewayEnvRecord
  ) => TConfig;
  defaultBaseURL?: string;
  defaultChatModel: string;
  getAdditionalIssues?: (
    resolvedEnv: AiGatewayResolvedEnv,
    env: AiGatewayEnvRecord
  ) => string[];
  missingApiKeyError: string;
  missingApiKeyIssue?: string;
}

const genericMissingApiKeyIssue =
  "AI_GATEWAY_API_KEY is missing. The demo can render, but chat requests will fail until it is configured.";

export function parseNodeVersion(version: string): ParsedNodeVersion {
  const match = nodeVersionPattern.exec(version);
  const major = Number(match?.[1]);
  const minor = Number(match?.[2]);
  const patch = Number(match?.[3]);

  if (![major, minor, patch].every(Number.isInteger)) {
    throw new Error(`Unable to parse Node.js version: "${version}".`);
  }

  return { major, minor, patch };
}

export function getNodeMajor(version: string): number {
  return parseNodeVersion(version).major;
}

function compareNodeVersions(
  left: ParsedNodeVersion,
  right: ParsedNodeVersion
): number {
  if (left.major !== right.major) {
    return left.major - right.major;
  }

  if (left.minor !== right.minor) {
    return left.minor - right.minor;
  }

  return left.patch - right.patch;
}

export function assertSupportedNodeRuntime(version = process.version): number {
  const parsedVersion = parseNodeVersion(version);
  const minimumVersion = parseNodeVersion(MINIMUM_NODE_VERSION);

  if (compareNodeVersions(parsedVersion, minimumVersion) < 0) {
    throw new Error(
      `Node.js ${version} is unsupported. This demo workspace requires Node.js >=${MINIMUM_NODE_VERSION}.`
    );
  }

  return parsedVersion.major;
}

export function resolveAiGatewayContractEnv(
  env: AiGatewayEnvRecord,
  options: Pick<AiGatewayContractOptions, "defaultBaseURL" | "defaultChatModel">
): AiGatewayResolvedEnv {
  return {
    apiKey: env.AI_GATEWAY_API_KEY,
    baseURL:
      env.AI_GATEWAY_BASE_URL ||
      options.defaultBaseURL ||
      DEFAULT_GATEWAY_BASE_URL,
    chatModel: env.AI_GATEWAY_CHAT_MODEL || options.defaultChatModel,
  };
}

export function readAiGatewayContractConfig(
  env: AiGatewayEnvRecord,
  options: AiGatewayContractOptions
): AiGatewayContractConfig {
  assertSupportedNodeRuntime();
  const resolvedEnv = resolveAiGatewayContractEnv(env, options);

  if (!resolvedEnv.apiKey) {
    throw new Error(options.missingApiKeyError);
  }

  return {
    apiKey: resolvedEnv.apiKey,
    baseURL: resolvedEnv.baseURL,
    chatModel: resolvedEnv.chatModel,
  };
}

export function buildAiGatewayContractSetupState<
  TConfig extends AiGatewaySetupConfig,
>(
  env: AiGatewayEnvRecord,
  options: AiGatewayContractOptions<TConfig>
): AiGatewayContractSetupState<TConfig> {
  const issues: string[] = [];
  const resolvedEnv = resolveAiGatewayContractEnv(env, options);

  try {
    assertSupportedNodeRuntime();
  } catch (error) {
    issues.push(
      error instanceof Error ? error.message : "Unsupported Node.js runtime."
    );
  }

  if (!resolvedEnv.apiKey) {
    issues.push(options.missingApiKeyIssue || genericMissingApiKeyIssue);
  }

  issues.push(...(options.getAdditionalIssues?.(resolvedEnv, env) ?? []));

  return {
    config:
      options.buildConfig?.(resolvedEnv, env) ??
      ({
        baseURL: resolvedEnv.baseURL,
        chatModel: resolvedEnv.chatModel,
      } as TConfig),
    isReady: issues.length === 0,
    issues,
    nodeVersion: process.version,
  };
}

export function createAiGatewayFromContract(
  env: AiGatewayEnvRecord,
  options: AiGatewayContractOptions
): ReturnType<typeof createGateway> {
  const { apiKey, baseURL } = readAiGatewayContractConfig(env, options);

  return createGateway({
    apiKey,
    baseURL,
  });
}

import { z } from "zod";

export const comparisonRatingSchema = z.enum([
  "weak",
  "mixed",
  "strong",
  "best",
]);

export const featureComparisonInputSchema = z.object({
  criteria: z
    .array(
      z.object({
        label: z.string().min(1).describe("Criterion name."),
        scores: z
          .array(
            z.object({
              option: z
                .string()
                .min(1)
                .describe("The option name this score refers to."),
              rating: comparisonRatingSchema.describe(
                "The relative score for this option on the criterion."
              ),
              summary: z
                .string()
                .min(1)
                .describe("Short, user-facing reason for the rating."),
            })
          )
          .min(1)
          .describe("Scores for the compared options."),
      })
    )
    .min(2)
    .max(6)
    .describe("Criteria used for the comparison matrix."),
  options: z
    .array(
      z.object({
        name: z.string().min(1).describe("Compared option name."),
        summary: z.string().min(1).describe("Short description of the option."),
      })
    )
    .min(2)
    .max(5)
    .describe("Options to compare."),
  subject: z.string().min(1).describe("What is being compared."),
  summary: z.string().min(1).describe("One-sentence comparison takeaway."),
});

export const featureComparisonOutputSchema =
  featureComparisonInputSchema.extend({
    kind: z.literal("feature-comparison"),
  });

export const planRecommendationInputSchema = z.object({
  alternatives: z
    .array(
      z.object({
        name: z.string().min(1).describe("Alternative option name."),
        tradeoff: z
          .string()
          .min(1)
          .describe("Main tradeoff versus the recommendation."),
      })
    )
    .min(1)
    .max(5)
    .describe("Credible alternatives considered."),
  decision: z
    .string()
    .min(1)
    .describe("The decision or choice the recommendation answers."),
  nextSteps: z
    .array(z.string().min(1))
    .min(1)
    .max(5)
    .describe("Concrete next actions for the user."),
  rationale: z
    .array(
      z.object({
        detail: z.string().min(1).describe("Reasoning detail."),
        label: z.string().min(1).describe("Reason label."),
      })
    )
    .min(1)
    .max(5)
    .describe("Reasons supporting the recommended option."),
  recommendedOption: z.object({
    name: z.string().min(1).describe("Recommended option name."),
    summary: z.string().min(1).describe("Why this option is recommended."),
  }),
  risks: z
    .array(
      z.object({
        mitigation: z
          .string()
          .min(1)
          .optional()
          .describe("How to reduce this risk."),
        risk: z.string().min(1).describe("Risk to watch."),
      })
    )
    .max(5)
    .describe("Risks or caveats for the recommendation."),
});

export const planRecommendationOutputSchema =
  planRecommendationInputSchema.extend({
    kind: z.literal("plan-recommendation"),
  });

export type FeatureComparisonInput = z.infer<
  typeof featureComparisonInputSchema
>;
export type FeatureComparisonOutput = z.infer<
  typeof featureComparisonOutputSchema
>;
export type PlanRecommendationInput = z.infer<
  typeof planRecommendationInputSchema
>;
export type PlanRecommendationOutput = z.infer<
  typeof planRecommendationOutputSchema
>;

export function createFeatureComparison(
  input: FeatureComparisonInput
): FeatureComparisonOutput {
  const parsedInput = featureComparisonInputSchema.parse(input);

  return {
    ...parsedInput,
    kind: "feature-comparison",
  };
}

export function createPlanRecommendation(
  input: PlanRecommendationInput
): PlanRecommendationOutput {
  const parsedInput = planRecommendationInputSchema.parse(input);

  return {
    ...parsedInput,
    kind: "plan-recommendation",
  };
}

export function getGenerativeUiAppEnv() {
  // biome-ignore lint/style/noProcessEnv: Registry source installs into consumer apps without this repo's env wrapper.
  return process.env;
}

import {
  type AiGatewayContractConfig,
  type AiGatewayContractSetupState,
  type AiGatewayEnvRecord,
  type AiGatewaySetupConfig,
  buildAiGatewayContractSetupState,
  createAiGatewayFromContract,
  readAiGatewayContractConfig,
} from "@/lib/ai-gateway/contract";
import { getGenerativeUiAppEnv } from "./env-source";
